var e=[{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`─안! ─에 피격당했─!`,JPN:`──アン！　──に攻撃され──！`,ENG:`–ian! –shot our wi–!`,TWN:`─內部！─被擊中─！`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`어떻─ 불시착을─`,JPN:`どうにかし──不時着を──`,ENG:`We hav– crash land so–!`,TWN:`必須——緊急降落——`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`으, 으윽…….`,JPN:`う、ううっ……`,ENG:`N-ngh...`,TWN:`呃…呃……`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L11_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`중사님! 움직이면 안 돼!`,JPN:`軍曹、動いちゃダメ！`,ENG:`Sergeant! You shouldn't be moving!`,TWN:`中士！你不能動！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`레이첼 씨, 어떻게 된 거예요…?`,JPN:`レイチェルさん、どうなったんですか……？`,ENG:`Rachel, what happened...?`,TWN:`瑞秋，怎麼回事……？`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`지금 비행 중인 거 아니었어요……?`,JPN:`今飛行中じゃないんですか……？`,ENG:`Weren't we flying just before...?`,TWN:`不是在飛行嗎……？`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`그, 그게……`,JPN:`そ、それが……`,ENG:`U-um...`,TWN:`那，那個……`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L15_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`바깥 상황이 조금 안 좋아.`,JPN:`外の状況がちょっとよくなくて。`,ENG:`The situation outside isn't that great.`,TWN:`外面的情況不太樂觀。`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L16_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`아니, 사실은 진짜 안 좋아! 적들이 너무 많아!`,JPN:`というか、ぶっちゃけめっちゃ悪い！　敵が多すぎ！`,ENG:`No, frankly, it's really bad! There are too many enemies!`,TWN:`不，應該說非常嚴重！敵人的數量太多了！`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`네……?`,JPN:`はい……？`,ENG:`What...?`,TWN:`嗯……？`},stage:{bg:`PROLOGUE_03`,slots:{L:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`호라이즌! 대형 침식체가 한 기 더 출몰했다!`,JPN:`ホライズン！　大型の侵食体がもう一匹出現した！`,ENG:`Horizon! Another large C.O. has appeared!`,TWN:`地平線！又出現了一隻大型侵蝕體！`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`HORIZON_COLD_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_SERIOUS`}}}},{id:`L22_1`,type:`dialog`,speaker:`HORIZON_COLD_NULL_NULL`,text:{KOREA:`장담하던 대로 정성이 과다 첨가된 공연이군요. 확인했습니다.`,JPN:`豪語したとおり、丹精が過剰に込められた公演ですね。確認しました。`,ENG:`Understood. What an extremely sincere performance, just as she promised.`,TWN:`果然是精心準備的演出，已確認。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`HORIZON_COLD_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_SERIOUS`}}}},{id:`L26_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`저건… 또다른 함선인가.`,JPN:`あれは……違う艦船か。`,ENG:`Is that... another ship?`,TWN:`那是……有一艘艦船。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`HORIZON_COLD_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_IDLE`},R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`기이하구나. 코러스를 인양하는 데에도 상당한 시일이 소모됐을진데, 이 규모의 선단이라니.`,JPN:`妙だな。コーラスを引き揚げるのにもかなりの時間を消費したはずだが、この規模の船団となると。`,ENG:`How strange. A fleet of this size... But it must have taken days to salvage Chorus.`,TWN:`不可思議。光是打撈Chorus就應該耗費不少時日，沒想到還能組建如此規模的船隊。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`HORIZON_COLD_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_IDLE`},R:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`}}}},{id:`L30_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`나도 돕고 싶었는데… 그만 격추당해 버렸어.`,JPN:`アタシも助けたかったんだけど……撃墜されちゃって。`,ENG:`I really wanted to help, but... I got shot down.`,TWN:`我本來想幫忙的…可惜被擊落了。`},stage:{bg:`PROLOGUE_03`,slots:{L:null,C:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};